import os
import json
import argparse
import heapq
import traceback
import glob
import numpy as np
from cogniplan_env import ExplorationEnv


def build_graph(nodes):
    coord_to_idx = {}
    coords = []
    for i, n in enumerate(nodes):
        c = tuple(np.round(np.array(n['coords']), 2))
        coord_to_idx[c] = i
        coords.append(np.array(n['coords'], dtype=float))
    adj = [[] for _ in range(len(nodes))]
    for i, n in enumerate(nodes):
        for nb in n.get('neighbors', []):
            ct = tuple(np.round(np.array(nb), 2))
            j = coord_to_idx.get(ct)
            if j is not None and j != i:
                d = float(np.linalg.norm(coords[i] - coords[j]))
                adj[i].append((j, d))
    return coord_to_idx, coords, adj


def dijkstra(adj, start):
    n = len(adj)
    dist = [float('inf')] * n
    prev = [-1] * n
    dist[start] = 0.0
    pq = [(0.0, start)]
    while pq:
        d, u = heapq.heappop(pq)
        if d > dist[u]:
            continue
        for v, w in adj[u]:
            nd = d + w
            if nd < dist[v]:
                dist[v] = nd
                prev[v] = u
                heapq.heappush(pq, (nd, v))
    return dist, prev


def path_first_step(prev, start, target):
    if target == start:
        return target
    if prev[target] == -1:
        return target
    cur = target
    while prev[cur] != start and prev[cur] != -1:
        cur = prev[cur]
    return cur


def pick_action(obs, last_target_coord):
    try:
        neighbors = obs['neighbors']
        nodes = obs['nodes']
        explored_rate = obs.get('explored_rate', 0.0)
    except Exception:
        return None, last_target_coord
    if not neighbors or not nodes:
        return None, last_target_coord
    try:
        robot = np.array(obs['robot_pos'], dtype=float)
        coord_to_idx, coords, adj = build_graph(nodes)
        if len(coords) == 0:
            return neighbors[0], last_target_coord
        dists_to_robot = [np.linalg.norm(c - robot) for c in coords]
        start_idx = int(np.argmin(dists_to_robot))
        dist, prev = dijkstra(adj, start_idx)

        late_phase = explored_rate >= 0.7

        scored = []
        for i, nd in enumerate(nodes):
            if i == start_idx:
                continue
            u = nd.get('utility', 0)
            if u <= 0:
                continue
            d = dist[i]
            if d == float('inf'):
                continue
            if late_phase:
                score = np.sqrt(u) / (d + 1.0)
            else:
                score = u / (d + 1.0)
            scored.append((score, i, u, d))
        scored.sort(reverse=True)

        if scored:
            target_idx = scored[0][1]
            if last_target_coord is not None:
                for sc, idx, u, d in scored[:5]:
                    if np.linalg.norm(coords[idx] - last_target_coord) < 0.5:
                        if sc >= scored[0][0] * 0.75:
                            target_idx = idx
                        break
            next_idx = path_first_step(prev, start_idx, target_idx)
            next_coord = coords[next_idx]
            chosen = min(neighbors, key=lambda c: np.linalg.norm(np.array(c) - next_coord))
            new_last = coords[target_idx].copy()
            return chosen, new_last
        else:
            best_d = float('inf')
            best_idx = -1
            for i, nd in enumerate(nodes):
                if i == start_idx:
                    continue
                if nd.get('visited', False):
                    continue
                d = dist[i]
                if d < best_d and d > 0:
                    best_d = d
                    best_idx = i
            if best_idx >= 0:
                next_idx = path_first_step(prev, start_idx, best_idx)
                next_coord = coords[next_idx]
                chosen = min(neighbors, key=lambda c: np.linalg.norm(np.array(c) - next_coord))
                return chosen, None
            return neighbors[0], None
    except Exception:
        traceback.print_exc()
        try:
            return neighbors[0], last_target_coord
        except Exception:
            return None, last_target_coord


def plan_episode(map_path, max_steps=128):
    env = ExplorationEnv(map_path=map_path)
    obs = env.reset()
    last_target_coord = None
    for step in range(max_steps):
        chosen, last_target_coord = pick_action(obs, last_target_coord)
        if chosen is None:
            break
        try:
            obs, info = env.step(chosen)
        except Exception:
            traceback.print_exc()
            break
        if info.get('done', False):
            break
    metrics = env.get_metrics()
    return metrics


def collect_episodes(data_path):
    """Return list of (map_abs_path, map_rel, env_type)."""
    episodes = []
    cfg_path = os.path.join(data_path, 'eval_config.json')
    maps_root_candidates = [
        os.path.join(data_path, 'maps_eval'),
        data_path,
    ]

    cfg = None
    if os.path.exists(cfg_path):
        try:
            with open(cfg_path) as f:
                cfg = json.load(f)
        except Exception:
            traceback.print_exc()
            cfg = None

    items = []
    if isinstance(cfg, dict):
        for key in ('episodes', 'maps', 'eval_episodes', 'tasks'):
            v = cfg.get(key)
            if isinstance(v, list) and v:
                items = v
                break
    elif isinstance(cfg, list):
        items = cfg

    def resolve(map_rel):
        if os.path.isabs(map_rel) and os.path.exists(map_rel):
            return map_rel
        for root in maps_root_candidates:
            p = os.path.join(root, map_rel)
            if os.path.exists(p):
                return p
        return None

    for it in items:
        try:
            if isinstance(it, str):
                map_rel = it
                env_type = map_rel.split('/')[0] if '/' in map_rel else 'unknown'
            elif isinstance(it, dict):
                map_rel = it.get('map_path') or it.get('map') or it.get('path') or it.get('file')
                env_type = it.get('env_type') or it.get('type')
                if not env_type and map_rel:
                    parts = map_rel.replace('\\', '/').split('/')
                    env_type = parts[-2] if len(parts) >= 2 else 'unknown'
            else:
                continue
            if not map_rel:
                continue
            ap = resolve(map_rel)
            if ap is None:
                # try basename in subdirs
                for root in maps_root_candidates:
                    matches = glob.glob(os.path.join(root, '**', os.path.basename(map_rel)), recursive=True)
                    if matches:
                        ap = matches[0]
                        break
            if ap is None:
                continue
            episodes.append((ap, map_rel, env_type or 'unknown'))
        except Exception:
            traceback.print_exc()
            continue

    if not episodes:
        # fallback: scan maps_eval/<type>/*.png
        for root in maps_root_candidates:
            if not os.path.isdir(root):
                continue
            for env_type in ('room', 'tunnel', 'outdoor'):
                tdir = os.path.join(root, env_type)
                if not os.path.isdir(tdir):
                    continue
                for fp in sorted(glob.glob(os.path.join(tdir, '*.png'))):
                    rel = os.path.join(env_type, os.path.basename(fp))
                    episodes.append((fp, rel, env_type))
            if episodes:
                break

    return episodes


def main():
    ap = argparse.ArgumentParser()
    ap.add_argument('--data_path', required=True)
    ap.add_argument('--checkpoint', required=False, default=None)
    ap.add_argument('--output', required=True)
    args = ap.parse_args()

    per_episode = []
    per_type = {}

    try:
        episodes = collect_episodes(args.data_path)
    except Exception:
        traceback.print_exc()
        episodes = []

    print(f'[predict] found {len(episodes)} episodes', flush=True)

    for map_path, map_rel, env_type in episodes:
        try:
            try:
                metrics = plan_episode(map_path)
            except Exception:
                traceback.print_exc()
                metrics = {'explored_rate': 0.0, 'travel_distance': 0.0, 'success': False, 'n_steps': 0}

            success = 1 if (metrics.get('success', False) or metrics.get('explored_rate', 0.0) > 0.9999) else 0
            travel_distance = float(metrics.get('travel_distance', 0.0))
            explored_rate = float(metrics.get('explored_rate', 0.0))

            entry = {
                'map_path': map_rel,
                'env_type': env_type or 'unknown',
                'success': success,
                'travel_distance': travel_distance,
                'explored_rate': explored_rate,
            }
            per_episode.append(entry)
            t = env_type or 'unknown'
            per_type.setdefault(t, []).append(entry)
        except Exception:
            traceback.print_exc()
            continue

    if per_episode:
        explored_mean = float(np.mean([e['explored_rate'] for e in per_episode]))
        succ_eps = [e for e in per_episode if e['success'] == 1]
        travel_mean = float(np.mean([e['travel_distance'] for e in succ_eps])) if succ_eps else 0.0
        success_rate = float(np.mean([e['success'] for e in per_episode]))
    else:
        explored_mean = 0.0
        travel_mean = 0.0
        success_rate = 0.0

    pt_summary = {}
    for t, eps in per_type.items():
        if not eps:
            continue
        em = float(np.mean([e['explored_rate'] for e in eps]))
        succ = [e for e in eps if e['success'] == 1]
        tm = float(np.mean([e['travel_distance'] for e in succ])) if succ else 0.0
        sr = float(np.mean([e['success'] for e in eps]))
        pt_summary[t] = {'explored_rate': em, 'travel_distance': tm, 'success_rate': sr}

    out = {
        'explored_rate': explored_mean,
        'travel_distance': travel_mean,
        'success_rate': success_rate,
        'per_episode': per_episode,
        'per_type': pt_summary,
        'total_episodes': len(per_episode),
    }

    try:
        with open(args.output, 'w') as f:
            json.dump(out, f)
    except Exception:
        traceback.print_exc()


if __name__ == '__main__':
    main()
